const dimensionKeys=["liquidez","seguridad","crecimiento","criterio","impacto"];
const dimensionLabels={liquidez:"Liquidez",seguridad:"Seguridad",crecimiento:"Crecimiento",criterio:"Criterio",impacto:"Impacto"};
function emptyImpact(){return dimensionKeys.reduce((a,k)=>(a[k]=0,a),{})}
function profileDefault(){return{...emptyImpact(),streak:0,lastDominant:"criterio",lastInsight:"Tu mapa financiero se construye con cada decisión."}}
function ensureProfile(){state.profile={...profileDefault(),...(state.profile||{})};return state.profile}
function focusDimension(focus){const f=String(focus||"").toLowerCase();if(f.includes("banca")||f.includes("ciber")||f.includes("seguridad")||f.includes("protección")||f.includes("clave"))return"seguridad";if(f.includes("invers")||f.includes("crecer")||f.includes("retorno")||f.includes("horizonte")||f.includes("diversificación"))return"crecimiento";if(f.includes("patrimonio")||f.includes("inflación")||f.includes("deflación")||f.includes("poder de compra")||f.includes("precios"))return"liquidez";if(f.includes("economía")||f.includes("mercado")||f.includes("demanda")||f.includes("regulación")||f.includes("proveedores"))return"impacto";return"criterio"}
function optionImpact(isCorrect,optionIndex,focus,level){const impact=emptyImpact(),main=focusDimension(focus);if(isCorrect){impact[main]+=3;impact.criterio+=2;impact.seguridad+=main==="seguridad"?2:1;if(level>=3)impact.impacto+=1;if(level===4)impact.crecimiento+=1}else{impact[main]-=2;impact.criterio-=1;if(optionIndex%2===0)impact.seguridad-=1;if(level>=3&&optionIndex%3===0)impact.liquidez-=1}return impact}
function lifeEffect(level,ctx,topic){const focus=ctx?.focus||"economía real";const lines={1:[`Esta decisión enseña que ${topic.toLowerCase()} afecta lo que puedes comprar hoy y guardar para después.`,`Aquí el dinero se entiende con una escena pequeña: precio, cuidado, permiso y elección.`,`El reto conecta ${topic.toLowerCase()} con hábitos que se repiten en casa y en la tienda.`],2:[`La decisión muestra cómo ${focus} aparece en apps, salidas, redes y compras reales.`,`Este paso entrena pausa, comparación y seguridad antes de gastar o invertir.`,`Tu elección conecta ${topic.toLowerCase()} con presupuesto, presión social y futuro cercano.`],3:[`La decisión afecta hogar, reserva, deuda, patrimonio y poder de compra.`,`Aquí se practica mirar flujo, riesgo, plazo y protección familiar antes de actuar.`,`Este reto convierte ${topic.toLowerCase()} en una decisión de estabilidad y futuro.`],4:[`La decisión mueve caja, margen, cliente, equipo y crecimiento.`,`Aquí el tema entra en economía real: precio, demanda, proveedor, riesgo y retorno.`,`Este paso une ${topic.toLowerCase()} con patrimonio, control y continuidad del negocio.`]};return lines[level][(topic.length+(ctx?.world||0))%3]}
function summarizeImpacts(mission,answers){const total=emptyImpact();mission.activities.forEach((a,i)=>{const impact=a.options[answers[i]]?.impact||emptyImpact();dimensionKeys.forEach(k=>total[k]+=impact[k]||0)});return total}
function dominantDimension(values){return dimensionKeys.slice().sort((a,b)=>(values[b]||0)-(values[a]||0))[0]||"criterio"}
function impactBadges(values){return dimensionKeys.map(k=>`<span><b>${dimensionLabels[k]}</b><em>${(values[k]||0)>0?"+":""}${values[k]||0}</em></span>`).join("")}
function profileInline(){const p=ensureProfile(),d=dominantDimension(p);return`<span class="pulse-line">Pulso financiero: ${dimensionLabels[d]} · racha ${p.streak||0}</span>`}
function coachingInsight(score,impact,level){const d=dominantDimension(impact),label=dimensionLabels[d];if(score>=90)return`Decisión maestra: tu fortaleza fue ${label}. Estás conectando dinero, riesgo y futuro con criterio propio.`;if(score>=80)return`Buen avance: ${label} fue tu eje. La siguiente mejora es explicar siempre el porqué de la decisión.`;return`Repite con foco en ${label}. No busques solo la respuesta correcta: mira qué cambia en tu dinero, seguridad y futuro.`}
function applyLearningImpact(impact,score,passed){const p=ensureProfile();dimensionKeys.forEach(k=>p[k]=Math.max(0,(p[k]||0)+(impact[k]||0)));p.streak=passed?(p.streak||0)+1:0;p.lastDominant=dominantDimension(impact);p.lastInsight=coachingInsight(score,impact,selectedLevel);return p.lastInsight}function economicFocus(level,i,a){const bank={1:["precios que suben y bajan","banco como lugar seguro para guardar","clave y permiso antes de usar tarjeta","cuidar lo que ya tienes como patrimonio","ahorrar antes de comprar","comparar antes de elegir"],2:["inflación y deflación en compras reales","banca digital y límites de seguridad","ciberseguridad: claves, enlaces y datos","inversión simulada y riesgo","patrimonio personal inicial","economía de apps, redes y suscripciones"],3:["inflación, deflación y poder de compra","banca, crédito, comisiones y fechas","ciberseguridad financiera y protección de datos","inversiones, diversificación y horizonte","gestión del patrimonio familiar","economía del hogar conectada con empleo, mercado e impuestos"],4:["inflación, deflación y precios del negocio","banca empresarial, caja y financiación","ciberseguridad de clientes, pagos y datos","inversión para crecer y retorno esperado","gestión del patrimonio empresarial y personal","economía real: proveedores, demanda, regulación y mercado"]};return bank[level][(i+a)%bank[level].length]}function dailyEconomyContext(level,i,a,topic){const world=Math.floor(i/10),slot=(i+a)%6;const bank={1:[["en una merienda del colegio","precio, cambio y elección sencilla"],["en una tienda del barrio","monedas, billetes y recibo"],["con una alcancía y una meta pequeña","ahorro, espera y deseo"],["en una compra familiar","lista, necesidad y presupuesto"],["cuidando útiles, ropa o juguetes","valor de las cosas y reparación"],["con una mascota o paseo familiar","gastos previstos e imprevistos"]],2:[["con la mesada de la semana","límite, registro y prioridad"],["en una salida con amigos","presión de grupo y costo real"],["en una app, juego o suscripción","pagos pequeños que se repiten"],["viendo una oferta en redes","impulso, comparación y seguridad"],["en un proyecto escolar o primer ingreso","trabajo, ahorro y decisión en equipo"],["planeando viaje, curso o compra grande","meta, plazo y costo de oportunidad"]],3:[["en el presupuesto mensual del hogar","ingresos, gastos fijos y reserva"],["al revisar banco, recibos y tarjetas","control, fechas y comisiones"],["ante una compra importante","comparación, garantía y costo total"],["con vivienda, transporte o alimentación","inflación doméstica y prioridades"],["frente a deuda, seguro o emergencia","riesgo, protección y plan B"],["pensando en patrimonio y futuro familiar","largo plazo, inversión y legado"]],4:[["con una idea de negocio real","cliente, problema y propuesta de valor"],["al poner precio a un producto o servicio","costo, margen y caja"],["con proveedores, inventario o entregas","control operativo y negociación"],["buscando ventas y confianza de clientes","canal, marca y ética"],["revisando impuestos, contratos o crédito","formalidad, obligaciones y riesgo"],["decidiendo si crecer o reinvertir","indicadores, equipo y continuidad"]]};const byWorld={0:["primer contacto","decisión pequeña","hábito inicial"],1:["herramienta práctica","información clara","comparación"],2:["autonomía","responsabilidad","protección"],3:["mercado","valor","intercambio"],4:["futuro","riesgo","crecimiento"]};const row=bank[level][slot],lens=byWorld[world][(i+a)%3];return{place:`${row[0]}, trabajando ${lens} de "${topic}"`,lens:row[1],focus:economicFocus(level,i,a),world}}let state=loadState(),selectedWorld=0,selectedLevel=state.level||1,onboardingLevel=selectedLevel,selectedEntrepreneurTrack="general",activeMission=null,activeQuestion=0,activeAnswers=[];ensureProfile();
