function cleanText(text){return String(text||"").replace(/\s*\(R\d+[A-Z]-\d+-\d+\)/g,"").replace(/\s*R\d+[A-Z]-\d+-\d+(?:-\d+)?/g,"").replace(/Intervenci[oó]n\s*:?\s*/gi,"").replace(/Tema\s+\d+\/50:?\s*/gi,"").trim()}
function shuffleOptions(list,seed){const a=list.slice();for(let i=a.length-1;i>0;i--){const j=(seed+i*7)%a.length;[a[i],a[j]]=[a[j],a[i]]}return a}
function wrongOptions(topic,level,a,place){const sets={1:["Comprar porque brilla mucho y pensar después","Guardar todo sin saber para qué","Elegir lo mismo que otra persona","No preguntar aunque tenga dudas","Olvidar el cambio y salir corriendo","Creer que una oferta siempre conviene"],2:["Aceptar la compra porque termina pronto","Pagar una suscripción sin revisar el mes","Comprar porque todos lo subieron a redes","Mirar solo la cuota pequeña","Confiar en una promesa demasiado perfecta","Decidir con enojo o emoción del momento"],3:["Resolver con crédito sin mirar intereses","Mover dinero del fondo sin reponerlo","Comprar por impulso para aliviar presión","Ignorar recibos y fechas","Elegir por costumbre sin comparar","Apostar todo a una sola opción"],4:["Vender mucho sin saber margen","Crecer porque parece emocionante","Aceptar cualquier cliente aunque pague tarde","Copiar el precio de otro negocio","Firmar sin revisar condiciones","Invertir todo sin plan B"]};const base=sets[level];return [0,1,2,3].map(n=>base[(a+n)%base.length])}
function capsuleText(topic,level,format,ctx){const byLevel={1:`Hoy practicas "${topic}" con una situación cercana: mirar, preguntar, contar y elegir sin prisa.`,2:`Este reto lleva "${topic}" a una decisión de día a día con apps, salidas, grupo o compras digitales.`,3:`Aquí "${topic}" se trabaja como una decisión de hogar: números, prioridad, riesgo y seguimiento.`,4:`En este reto "${topic}" entra en modo negocio: cliente, caja, margen, control y siguiente paso.`};return `${byLevel[level]} Se trabaja desde ${ctx?.lens||"economía cotidiana"} y ${ctx?.focus||"economía real"}. Formato: ${format}.`}
function expressActivity(level,topic,place,guideName){const childActs=[`${guideName} salta al mostrador: mira tres precios imaginarios y elige cuál necesitas de verdad.`,`${guideName} toca la alcancía: separa una moneda para guardar y otra para usar.`,`${guideName} levanta la patita: antes de responder, cuenta hasta tres y piensa si es necesidad o deseo.`,`${guideName} señala el recibo: busca qué se pagó, cuánto costó y si hubo cambio.`];const teenActs=[`${guideName} activa modo pausa: revisa precio, envío, suscripción y fecha antes de decidir.`,`${guideName} te reta a comparar: una opción rápida, una barata y una que conviene a futuro.`,`${guideName} cambia la presión del grupo: decide sin copiar lo que todos quieren.`,`${guideName} abre la calculadora mental: separa gasto, ahorro y margen para imprevistos.`];if(level===1)return childActs[topic.length%childActs.length];if(level===2)return teenActs[topic.length%teenActs.length];return `${guideName} te propone una pausa de decisión: mira números, riesgo y siguiente paso antes de responder.`}
function characterLines(level,topic,place,g,support,format){const openers={1:[`Tengo una duda sencilla sobre ${topic}: vamos paso a paso.`,`Mira conmigo esta situación ${place}; primero contamos y luego elegimos.`,`Te acompaño: si algo parece brillante, respiramos y revisamos.`],2:[`Te pongo una escena real ${place}; no respondas por presión.`,`Antes de tocar el botón, revisa costo real, límite y consecuencia.`,`Vamos a detectar la trampa de la prisa y decidir con cabeza fría.`],3:[`Abrimos el tablero adulto: ingreso, obligación, reserva y objetivo.`,`Esta decisión necesita datos, no solo costumbre.`,`Pensemos en estabilidad: hoy, mes próximo y plan B.`],4:[`Entremos al negocio: cliente, costo, margen y caja.`,`Esta decisión debe sostenerse con números y condiciones claras.`,`Miremos crecimiento sin perder control.`]};const nudges={1:[`Yo cambio el reto: imagina que alguien te apura para comprar.`,`Yo te ayudo: si dudas, pregunta a un adulto y revisa el cambio.`,`Pista rápida: necesidad primero, capricho después.`],2:[`Cambio de escenario: aparece una oferta con contador de tiempo.`,`Pista: una app fácil también puede esconder cargos.`,`Respira: que todos lo quieran no significa que te convenga.`],3:[`Cambio el escenario: llega un gasto inesperado y toca priorizar.`,`Pista: una buena respuesta deja fecha, monto y revisión.`,`Mira el costo total antes de decidir.`],4:[`Cambio el escenario: el cliente quiere más plazo para pagar.`,`Pista: caja primero, crecimiento después.`,`Si no puedes medirlo, no lo escales todavía.`]};return{guideLine:openers[level][(topic.length+format.length)%3],supportLine:nudges[level][(topic.length+place.length)%3],actionLine:expressActivity(level,topic,place,g.name)}}function buildModules(level){return topicsForLevel(level).map((topic,i)=>({id:i+1,code:`M${i+1}`,topic,worldIndex:Math.floor(i/10),localIndex:i%10,country:worlds[Math.floor(i/10)].countries[i%10],activities:evaluationTypes.map((_,a)=>activity(topic,i,a,level))}))}
function activity(topic,i,a,level){const d=levelDynamics[level],ev=evaluationTypes[a],basePlace=d.places[(i+a)%d.places.length],ctx=dailyEconomyContext(level,i,a,topic),place=ctx.place||basePlace,nums=d.amounts[(i+a)%d.amounts.length],keep=nums[1],left=nums[0]-nums[1],seed=i*9+a+level*1000,track=level===4&&selectedEntrepreneurTrack==="woman"?"W":"G",caseId=`R${level}${track}-${i+1}-${a+1}`;const sets={1:[[`${place}: ¿Qué debe hacer primero con "${topic}"?`,"Mirar el dinero, preguntar y decidir despacio"],[`Completa la idea de "${topic}" con palabras muy simples.`,"Es una forma de cuidar el dinero con una acción concreta"],[`¿Qué ejemplo practica mejor "${topic}"?`,"Usarlo en una compra pequeña con ayuda de un adulto"],[`Elige la decisión más cuidadosa sobre "${topic}".`,"Comprar solo si alcanza y guardar una parte"],[`Si tiene $${nums[0]} y guarda $${keep}, ¿cuánto puede usar sin tocar su ahorro?`,`$${left}`],[`Ordena la forma más segura de practicar "${topic}".`,"Pensar, contar, preguntar y decidir"],[`Aparece una sorpresa ${place}. ¿Qué respuesta cuida el dinero?`,"Parar, contar cuánto queda y pedir ayuda si hace falta"],[`¿Qué explicación podría dar a otro niño sobre "${topic}"?`,"Lo explico con palabras simples y un ejemplo de casa"],[`¿Qué plan pequeño sirve para "${topic}" esta semana?`,"Guardar una parte, anotar la meta y revisar al final"]],2:[[`${place}: ¿Qué revisa primero para "${topic}"?`,"Dinero disponible, costo real y consecuencia"],[`Elige la definición útil de "${topic}".`,"Es una decisión que afecta mi dinero de hoy y de después"],[`¿Qué ejemplo muestra buen uso de "${topic}"?`,"Comparar, leer condiciones y decidir con presupuesto"],[`¿Qué decisión protege su avance?`,"Elegir según prioridad, límite y fecha de revisión"],[`Si recibe $${nums[0]} y separa $${keep}, ¿cuánto queda para gastar?`,`$${left}`],[`Ordena una rutina sana para "${topic}".`,"Meta, presupuesto, compra y revisión"],[`Sube el precio ${place}. ¿Qué respuesta es madura?`,"Pausar, ajustar el plan y decidir si aún conviene"],[`¿Qué explicación demuestra que lo entendió?`,"Explica costo, riesgo, beneficio y decisión tomada"],[`¿Qué plan sirve para avanzar con "${topic}"?`,"Anotar ingresos, límites, meta y próxima revisión"]],3:[[`${place}: ¿Qué dato abre el análisis de "${topic}"?`,"Ingreso neto, obligaciones y reserva disponible"],[`Elige la definición adulta de "${topic}".`,"Debe conectarse con flujo, riesgo, plazo y objetivo"],[`¿Qué ejemplo muestra buena práctica?`,"Separar, registrar y decidir con evidencia"],[`¿Qué decisión es más prudente?`,"Comparar costo total, plazo y consecuencia"],[`Si entran $${nums[0]} y reserva $${keep}, ¿cuánto queda para obligaciones y gastos?`,`$${left}`],[`Ordena un proceso adulto para "${topic}".`,"Diagnóstico, objetivo, opciones, decisión y seguimiento"],[`Surge un imprevisto ${place}. ¿Qué acción cuida estabilidad?`,"Usar la reserva si aplica y reponerla después"],[`¿Qué explicación demuestra dominio?`,"Incluye motivo, números básicos, riesgo y siguiente paso"],[`¿Qué plan adulto queda completo?`,"Fecha, monto, responsable, límite y revisión"]],4:[[`${place}: ¿Qué valida primero para "${topic}"?`,"Cliente, problema, costo y capacidad de pago"],[`Elige la definición empresarial de "${topic}".`,"Debe mejorar caja, margen, control o aprendizaje"],[`¿Qué ejemplo muestra disciplina?`,"Registrar ingresos, costos y decisiones"],[`¿Qué decisión protege el negocio?`,"Medir costo total antes de vender, comprar o endeudarse"],[`Si vende por $${nums[0]} y cuesta $${keep} producir, ¿qué queda antes de otros gastos?`,`$${left}`],[`Ordena una ruta de crecimiento para "${topic}".`,"Validar, medir, vender, cobrar y reinvertir"],[`Un cliente o proveedor cambia condiciones ${place}. ¿Qué haces?`,"Revisar caja, contrato, riesgo y ajustar condiciones"],[`¿Qué explicación darías a una socia o mentor?`,"Situación, números, riesgo y decisión recomendada"],[`¿Qué plan empresarial queda completo?`,"Meta, presupuesto, indicador, fecha y revisión"]]};const row=sets[level][a],wrong=wrongOptions(topic,level,a,place),rot=shuffleOptions([row[1],...wrong],seed).slice(0,4);if(!rot.includes(row[1]))rot[seed%4]=row[1];return{id:caseId,name:ev.label,answerFormat:ev.mode,topic,question:cleanText(row[0]),options:rot.map((x,n)=>{const ok=x===row[1];return{text:cleanText(x),isCorrect:ok,impact:optionImpact(ok,n,ctx.focus,level)}}),economyLens:ctx.focus,lifeEffect:lifeEffect(level,ctx,topic),decisionDimension:focusDimension(ctx.focus),capsule:capsuleText(topic,level,ev.mode,ctx),tip:["Primero mira lo que necesitas; después decide si el deseo encaja.","Una buena decisión aguanta una pausa y una segunda mirada.","Comparar protege contra la prisa, la presión, los cambios de precios y las ofertas que brillan demasiado.","Los números pequeños también cuentan cuando se repiten, suben, bajan o se convierten en deuda.","La mejor respuesta deja claro qué harás ahora y qué revisarás después."][(i+a)%5],place}}
function loadState(){const f={playerName:"",studentId:"",createdAt:"",updatedAt:"",tokens:0,level:1,unlocked:1,completed:{},scores:{},attempts:[]};try{if(location.search.includes("reset=1")){localStorage.removeItem(STORAGE_KEY);return f}return{...f,...JSON.parse(localStorage.getItem(STORAGE_KEY)||"{}")}}catch{return f}}
function saveState(){state.updatedAt=new Date().toISOString();try{localStorage.setItem(STORAGE_KEY,JSON.stringify(state))}catch{}}
async function initFirebase(){const ext=window.JUEGO_DINERO_FIREBASE||{};const settings={...FIREBASE_SETTINGS,...ext,config:{...FIREBASE_SETTINGS.config,...(ext.config||{})}};if(!settings.enabled||!settings.config.projectId)return;try{const appM=await import("https://www.gstatic.com/firebasejs/10.12.5/firebase-app.js");const fireM=await import("https://www.gstatic.com/firebasejs/10.12.5/firebase-firestore.js");const app=appM.initializeApp(settings.config);firebaseDb=fireM.getFirestore(app);firebaseApi=fireM;firebaseReady=true;try{if(settings.config.measurementId){const analyticsM=await import("https://www.gstatic.com/firebasejs/10.12.5/firebase-analytics.js");firebaseAnalytics=analyticsM.getAnalytics(app)}}catch(e){console.warn("Firebase Analytics no pudo iniciar",e)}renderFirebaseStatus()}catch(e){console.warn("Firebase no pudo iniciar",e);renderFirebaseStatus("Tu avance se guardará en este equipo")}}
function init(){document.body.dataset.level=selectedLevel;initFirebase();setupOnboarding();setupEntrepreneurTabs();renderCompanions();document.getElementById("name-form").addEventListener("submit",e=>{e.preventDefault();const name=document.getElementById("player-name").value.trim();if(!name)return;state.playerName=name;if(!state.studentId)state.studentId=`STD-${Date.now()}-${Math.random().toString(36).slice(2,8).toUpperCase()}`;if(!state.createdAt)state.createdAt=new Date().toISOString();selectedLevel=onboardingLevel;state.level=selectedLevel;document.body.dataset.level=selectedLevel;modules=buildModules(selectedLevel);saveState();showGame()});document.querySelectorAll(".levels button[data-level]").forEach(b=>b.onclick=()=>{selectedLevel=+b.dataset.level;state.level=selectedLevel;document.body.dataset.level=selectedLevel;modules=buildModules(selectedLevel);saveState();render();refreshParticles&&refreshParticles()});document.getElementById("close-mission").onclick=()=>document.getElementById("mission").close();document.getElementById("close-certificate").onclick=()=>document.getElementById("certificate").close();document.getElementById("save-progress").onclick=()=>manualSaveProgress();if(state.playerName)showGame();particles()}
function setupOnboarding(){document.querySelectorAll("[data-onboard-level]").forEach(b=>{b.classList.toggle("active",+b.dataset.onboardLevel===onboardingLevel);b.onclick=()=>{onboardingLevel=+b.dataset.onboardLevel;selectedLevel=onboardingLevel;document.body.dataset.level=selectedLevel;setupOnboarding();renderCompanions();refreshParticles&&refreshParticles()}})}
function setupEntrepreneurTabs(){document.querySelectorAll("[data-track]").forEach(b=>b.onclick=()=>{selectedEntrepreneurTrack=b.dataset.track;modules=buildModules(selectedLevel);render()})}
function renderEntrepreneurTabs(){const tabs=document.getElementById("entrepreneur-tabs");if(!tabs)return;tabs.classList.toggle("hidden",selectedLevel!==4);tabs.querySelectorAll("[data-track]").forEach(b=>b.classList.toggle("active",b.dataset.track===selectedEntrepreneurTrack))}
function pair(w,l){const p=pools[l];return l===1?[p[w*2],p[w*2+1]]:[p[(w*2)%p.length],p[(w*2+1)%p.length]]}
function guide(m){return pair(m.worldIndex,selectedLevel)[m.localIndex%2]}
function renderCompanions(){const p=pair(0,onboardingLevel);document.getElementById("companions").innerHTML=`<div class="mini">${avatar(p[0])}</div><div class="mini">${avatar(p[1])}</div><div class="copy"><b>${p[0].name} y ${p[1].name} abren tu ruta</b><span>${levels[onboardingLevel].intro}. Cada reto trae un imprevisto.</span></div>`}
function showGame(){document.getElementById("onboarding").classList.add("hidden");document.getElementById("game").classList.remove("hidden");render()}
function render(){if(!state.playerName)return;document.getElementById("welcome").textContent=`Hola, ${state.playerName}`;document.getElementById("tokens").textContent=state.tokens;document.getElementById("done").textContent=`${Object.keys(state.completed).length}/50`;const vals=Object.values(state.scores);document.getElementById("score").textContent=(vals.length?vals[vals.length-1]:0)+"%";document.querySelectorAll(".levels button[data-level]").forEach(b=>b.classList.toggle("active",+b.dataset.level===selectedLevel));renderEntrepreneurTabs();renderFirebaseStatus();renderWorlds();renderMap()}
function renderFirebaseStatus(msg){const s=document.getElementById("firebase-status");if(!s)return;if(msg){s.className=firebaseReady?"firebase-status online":"firebase-status local";s.textContent=msg;return}if(firebaseReady){s.className="firebase-status online";s.textContent="Tu avance está protegido"}else{s.className="firebase-status local";s.textContent="Avance listo para guardar"}}
function manualSaveProgress(){saveState();renderFirebaseStatus("Guardando tu avance...");syncProgress("Avance guardado")}
function renderWorlds(){const box=document.getElementById("world-buttons");box.innerHTML="";worlds.forEach((w,i)=>{const done=modules.filter(m=>m.worldIndex===i&&state.completed[m.id]).length,p=pair(i,selectedLevel),b=document.createElement("button");b.className=i===selectedWorld?"active":"";b.innerHTML=`<strong>${w.region}: ${w.name}</strong><small>${p[0].name} + ${p[1].name} · ${done}/10 zonas</small>`;b.onclick=()=>{selectedWorld=i;render();refreshParticles&&refreshParticles()};box.appendChild(b);if(done===10){const c=document.createElement("button");c.textContent=`Emitir certificado: ${w.name}`;c.onclick=()=>openCertificate(i);box.appendChild(c)}})}
function renderMap(){const w=worlds[selectedWorld],p=pair(selectedWorld,selectedLevel);document.getElementById("world-region").textContent=w.region;document.getElementById("world-title").textContent=w.name;document.getElementById("world-description").innerHTML=`${w.description} Guias activos: ${p[0].name} y ${p[1].name}. ${profileInline()}`;const map=document.getElementById("map");map.innerHTML=`<div class="continent" style="--world-color:${w.color};clip-path:${w.shape}"></div>`;const pos=positions[selectedWorld],mods=modules.filter(m=>m.worldIndex===selectedWorld);pos.slice(0,-1).forEach((a,i)=>route(map,a,pos[i+1]));mods.forEach((m,i)=>{const g=guide(m),b=document.createElement("button"),[l,t]=pos[i];b.className=`node ${state.completed[m.id]?"done":""}`;b.style.left=l+"%";b.style.top=t+"%";b.style.borderColor=m.id<=state.unlocked?w.color:"";b.disabled=m.id>state.unlocked;b.innerHTML=`<b>${m.code}</b><small>${m.country}</small><em>${g.name}</em>`;b.onclick=()=>openMission(m);map.appendChild(b)})}
