function openMission(m){activeMission=m;activeQuestion=0;activeAnswers=[];renderMission();openDialog(document.getElementById("mission"))}
function renderMission(){const total=activeMission.activities.length,a=activeMission.activities[activeQuestion],g=guide(activeMission),p=pair(activeMission.worldIndex,selectedLevel),support=p.find(x=>x.name!==g.name)||p[0],sur=surprises[selectedLevel][(activeMission.id+activeQuestion)%5],lines=characterLines(selectedLevel,activeMission.topic,a.place,g,support,a.answerFormat);document.getElementById("mission-content").innerHTML=`<div class="mission-body"><div class="pill-row"><span class="pill">${activeMission.country}</span><span class="pill">${levels[selectedLevel].name}</span><span class="pill">${levels[selectedLevel].duration} min</span><span class="pill">${a.answerFormat}</span></div><div class="mission-grid"><aside class="card"><div class="guide-duo live-guides">${mini(g,"lead")}${mini(support,"support")}</div><div class="interaction"><p><b>${g.name}</b>: ${lines.guideLine}</p><p><b>${support.name}</b>: ${lines.supportLine}</p><p class="express"><b>Actividad express</b>: ${lines.actionLine}</p></div></aside><section><div class="capsule"><p class="brand-p">Reto activo</p><h3>${activeMission.topic}</h3><p>${a.capsule}</p><div class="decision-lab"><span>Economía viva</span><strong>${a.economyLens}</strong><small>${a.lifeEffect}</small></div><p>${a.tip}</p></div><div class="surprise"><p>Imprevisto del día</p><h3>${sur}</h3><p>${support.name} cambia el escenario: responde como si acabara de pasar.</p></div><div class="card"><h3>${a.question}</h3><div class="options">${a.options.map((o,i)=>`<button data-option="${i}" class="${activeAnswers[activeQuestion]===i?"selected":""}">${o.text}</button>`).join("")}</div></div><div class="actions"><button class="secondary" id="prev" ${activeQuestion===0?"disabled":""}>Anterior</button><button id="next" ${activeAnswers[activeQuestion]===undefined?"disabled":""}>${activeQuestion===total-1?"Calificar":"Siguiente"}</button></div></section></div></div>`;document.querySelectorAll("[data-option]").forEach(b=>b.onclick=()=>{document.querySelectorAll("[data-option]").forEach(x=>x.classList.remove("selected"));b.classList.add("selected");activeAnswers[activeQuestion]=+b.dataset.option;document.getElementById("next").disabled=false});document.getElementById("prev").onclick=()=>{if(activeQuestion>0){activeQuestion--;renderMission()}};document.getElementById("next").onclick=()=>{activeQuestion<total-1?(activeQuestion++,renderMission()):grade()}}
function mini(c,role=""){return`<div class="guide ${role}"><div class="avatar">${avatar(c)}</div><h3>${c.name}</h3><p>${c.species}</p></div>`}
